local UIMainControlTool = class("UIMainControlTool", IGUILayout)

local cdNextAreaEventKey = nil
local cdAreaEventKey = nil

nextAreaEventCd = 0
areaEventCd = 0

function UIMainControlTool:onLoad()
    self.countdown = 0
    self.effectCount = 0

    self.tvGoldText = self:getChildWindow("LiftingSimulatorMainTool-GoldText", GUIType.StaticText)
    self.btnGoldButton = self:getChildWindow("LiftingSimulatorMainTool-GoldButton", GUIType.Button)
    self.tvCountdown = self:getChildWindow("LiftingSimulatorMainTool-Countdown", GUIType.StaticText)
    self.tvAreaEventCountdown = self:getChildWindow("LiftingSimulatorMainTool-AreaEvent-Countdown", GUIType.StaticText)
    self.ivUpArrow = self:getChildWindow("LiftingSimulatorMainTool-UpArrow", GUIType.StaticImage)
    --self.ivUpArrow:SetEffectName("g1055_ui_coin.effect")
    --self.ivUpArrow:SetArea({ 0.785156, 0}, { 0, 10 }, { 0, 70 }, { 0, 70 })
    self.ivUpArrow:SetVisible(false)
    self.cbPayShopCheck = self:getChildWindow("LiftingSimulatorMainTool-CheckAppShop")
    self.btnNewGuide = self:getChildWindow("LiftingSimulatorMainTool-New-Guide-Btn")

    self.cbPayShopCheck:registerEvent(GUIEvent.Click, function()
        self:onClickPayShop()

        local data = DataBuilder.new():addParam("ClickPayShop", "nil"):getData()
        PacketSender:sendLuaCommonData("DoReport", data)
    end)

    local player = PlayerManager:getClientPlayer()
    if player == nil then
        return
    end

    --用于打开商店
    self.btnGoldButton:registerEvent(GUIEvent.ButtonClick, function()
        self:onGoldClick()
    end)

    self.btnNewGuide:registerEvent(GUIEvent.ButtonClick, function()
        self:onNewGuideClick()
    end)

    self:registerEvent(S2CCaptainUpArrow, function(data)
        self:onCaptainUpArrow(data)
    end)
    --用于新金币值
    self:registerEvent(S2CLSGoldUpdate, function(data)
        self:onGoldUpdate(data)
    end)

    --KO特效
    self:registerEvent(S2CWrestlingKOEffect, function(data)
        self:showCenterEffect(GameConfig.koEffect, GameConfig.koEffectTime)
    end)

    --Boss出现，开始进阶
    self:registerEvent(S2CLSStartAdvanced, function(data)
        player.property.isAdvancing = true
        local countdown = data:getNumberParam("countdown")
        self:startCountdown(countdown)
        GUIMainControl:showGameTip("start.advanced", 2000)
    end)

    --进阶结果
    self:registerEvent(S2CLSAdvancedResult, function(data)
        self:endCountdown()
        local isWin = data:getBoolParam("isWin")
        if isWin then
            self:showCenterEffect("129_victory.effect", 5000)
        else
            self:showCenterEffect("128_defeat.effect", 5000)
        end
        if isWin then
            GUIMainControl:onBossDead()
        end
    end)

    --加入进阶场景
    self:registerDataCallBack("JoinAdvanced", function(data)
        player.property.isAdvancing = true
        if GUIMainControl.selectMode ~= Define.SelectMode.Punch then
            GUIMainControl:onButtonSelect(Define.SelectMode.Punch)
        end
    end)

    --退出进阶场景
    self:registerDataCallBack("QuitAdvanced", function(data)
        player.property.isAdvancing = false
        if GUIMainControl.selectMode ~= Define.SelectMode.Equip then
            GUIMainControl:onButtonSelect(Define.SelectMode.Equip)
        end
        GUIMainControl:setBossHpVisible(false)
    end)

    self:registerEvent(MainControlToolGoldUpdateEvent, function()
        self:onDoubleGoldBuySuccess()
    end)

    --self.btnGoldButton:SetVisible(false)
    self.tvCountdown:SetVisible(false)

    --清除切换视角按钮点击事件
    GUIManager:getWindowByName("ToolBar-Perspece"):removeAllEvents()
end

function UIMainControlTool:onDoubleGoldBuySuccess()

    --print("***********************************")
    local onePrivilege = PayItemConfig:getPayItemByType(Define.PayItemType.DoubleGold)
    --print(json.encode(onePrivilege))
    if onePrivilege and onePrivilege.Status == PayItemBuyStatus.Used then
        self.btnGoldButton:SetVisible(false)
    end

end

function UIMainControlTool:onCaptainUpArrow(data)

    local builder = DataBuilder.new():fromData(data)
    local isVisible = builder:getBoolParam("isVisible")
    if isVisible then
        self.ivUpArrow:SetVisible(true)
    else
        self.ivUpArrow:SetVisible(false)
    end

end

function UIMainControlTool:onGoldClick()
    if not self:isLoad() then
        return
    end
    --增加打开商店代码
    ToolBarGoldClickEvent:invoke()

    local onePrivilege = PayItemConfig:getPayItemByType(Define.PayItemType.DoubleGold)

    CheckMoneyContent:setCurrencyInfo(PayHelper.getMoneyIcon(MoneyType.Diamonds), onePrivilege.Price)
    CheckMoneyContent:setContentText(Lang:getString("gui_double_gold_point"))
    CheckMoneyContent:setCurrencyTip(Lang:getString("gui_auto_workout_tip"))
    CheckMoneyContent:setCurrencyNum(tostring(onePrivilege.Price) .. Lang:getString("gui_auto_workout_text"))

    local sureListener = function()
        LuaTimer:schedule(function()
            MainControlCustomDialogClickEvent:invoke(PayTabKind.Privilege, onePrivilege.Id)
        end, 0)

        local data = DataBuilder.new():addParam("ClickGold", "sure"):getData()
        PacketSender:sendLuaCommonData("DoReport", data)
    end

    local cancelListener = function()
        local data = DataBuilder.new():addParam("ClickGold", "cancel"):getData()
        PacketSender:sendLuaCommonData("DoReport", data)
    end

    CustomDialog.builder()
                .setContentView(CheckMoneyContent)
                .setRightClickListener(sureListener)
                .setLeftClickListener(cancelListener)
                .setCloseClickListener(cancelListener)
                .show()
end

function UIMainControlTool:isMainLayout()
    return true
end

function UIMainControlTool:onTick(frameTime)
    if self.tvCountdown:IsVisible() then
        self.tvAreaEventCountdown:SetVisible(false)
    end
end

function UIMainControlTool:onGoldUpdate(data)
    if not self:isLoad() then
        return
    end

    local builder = DataBuilder.new():fromData(data)
    local curGold = builder:getParam("curGold")
    self.tvGoldText:SetText(Utility.toKMBString(curGold, 4))
    GoldChangeEvent:invoke(BigNum.new(curGold))
    --print("UIMainControlTool:onGoldUpdate " .. curGold)
end

function UIMainControlTool:startCountdown(countdown)
    self:endCountdown()
    self.countdown = countdown
    self.tvCountdown:SetVisible(true)
    self.tvCountdown:SetText(Lang:getString("countdown.text") .. self.countdown)
    self.countdownKey = LuaTimer:schedule(function()
        self.countdown = self.countdown - 1
        if self.countdown <= 0 then
            self:endCountdown()
        end
        self.tvCountdown:SetText(Lang:getString("countdown.text") .. self.countdown)
    end, 1000, 1000)
end

function UIMainControlTool:endCountdown()
    if self.countdownKey ~= nil then
        LuaTimer:cancel(self.countdownKey)
        self.countdownKey = nil
    end
    self.tvCountdown:SetVisible(false)
end

function UIMainControlTool:startNextAreaEventCd(countdown)
    self:endAreaEventCd(cdNextAreaEventKey)
    self:endAreaEventCd(cdAreaEventKey)
    nextAreaEventCd = countdown
    self.tvAreaEventCountdown:SetVisible(true)

    cdNextAreaEventKey = LuaTimer:schedule(function()
        self:nextAreaEventCdTimer()
    end, 0, 1000)

    LogUtil.log(string.format("UIMainControlTool:startNextAreaEventCd %d %d", countdown, cdNextAreaEventKey))
end

function UIMainControlTool:nextAreaEventCdTimer()
    nextAreaEventCd = nextAreaEventCd - 1
    if nextAreaEventCd <= 0 then
        self:endAreaEventCd(cdNextAreaEventKey)
    end
    self.tvAreaEventCountdown:SetText(Lang:getString("NextAreaEventCd.text") .. nextAreaEventCd)
    LogUtil.log(string.format("startNextAreaEventCd self.tvAreaEventCountdown:SetText %d", nextAreaEventCd))
end

function UIMainControlTool:startAreaEventCd(eventTime, needMuscle, rewardType, rewardNum)
    self:endAreaEventCd(cdNextAreaEventKey)
    self:endAreaEventCd(cdAreaEventKey)
    areaEventCd = eventTime
    self.tvAreaEventCountdown:SetVisible(true)

    cdAreaEventKey = LuaTimer:schedule(function()
        areaEventCd = areaEventCd - 1
        if areaEventCd <= 0 then
            self:endAreaEventCd(cdAreaEventKey)
        end
        local strRewardType = Lang:getString("reward_type_" .. rewardType)
        self.tvAreaEventCountdown:SetText(string.format(Lang:getString("AreaEventCd.text") .. strRewardType,
                areaEventCd, Utility.toKMBString(tostring(rewardNum), 2)))
        LogUtil.log(string.format("startAreaEventCd self.tvAreaEventCountdown:SetText %d", areaEventCd))
    end, 0, 1000)

    LogUtil.log(string.format("UIMainControlTool:startAreaEventCd %d %d %d %d %d",
            eventTime, needMuscle, rewardType, rewardNum, cdAreaEventKey))
end

function UIMainControlTool:endAreaEventCd(key)
    LuaTimer:cancel(key)
    key = nil
    self.tvAreaEventCountdown:SetVisible(false)
end

function UIMainControlTool:showCenterEffect(effect, duration)
    self.effectCount = self.effectCount + 1
    local name = "UIMainControlTool-Effect-" .. self.effectCount
    local ivEffect = GUIManager:createGUIWindow(GUIType.StaticImage, name)
    ivEffect:SetWidth({ 0, 380 })
    ivEffect:SetHeight({ 0, 270 })
    ivEffect:SetYPosition({ 0, 200 })
    ivEffect:SetHorizontalAlignment(HorizontalAlignment.Center)
    ivEffect:SetVerticalAlignment(VerticalAlignment.Center)
    ivEffect:SetVisible(true)
    ivEffect:SetEffectName(effect)
    self.root:AddChildWindow(ivEffect)
    LuaTimer:schedule(function()
        self.root:RemoveChildWindow(ivEffect:GetName())
        GUIManager:destroyGUIWindow(ivEffect)
    end, duration)
end

function UIMainControlTool:onClickPayShop()

    --print("+++++++++++++++++++++++++++++++++++++++++")
    PayShopToolbarClickEvent:invoke()
end

function UIMainControlTool:onNewGuideClick()
    ToolBarNewGuideClickEvent:invoke()
end

return UIMainControlTool